8	#include <njs_main.h>
9	
10	
11	static njs_int_t njs_function_native_call(njs_vm_t *vm, njs_value_t *retval);
12	
13	
14	njs_function_t *
15	njs_function_alloc(njs_vm_t *vm, njs_function_lambda_t *lambda,
16	    njs_bool_t async)
17	{
18	    size_t          size;
19	    njs_object_t    *proto;
20	    njs_function_t  *function;
21	
22	    size = sizeof(njs_function_t) + lambda->nclosures * sizeof(njs_value_t *);
23	
24	    function = njs_mp_zalloc(vm->mem_pool, size);
25	    if (njs_slow_path(function == NULL)) {
26	        goto fail;
27	    }
28	
29	    /*
30	     * njs_mp_zalloc() does also:
31	     *   njs_flathsh_init(&function->object.hash);
32	     *   function->object.__proto__ = NULL;
33	     */
34	
35	    function->ctor = lambda->ctor;
36	    function->u.lambda = lambda;
37	
38	    if (function->ctor) {
39	        function->object.shared_hash = vm->shared->function_instance_hash;
40	
41	    } else if (async) {
42	        function->object.shared_hash = vm->shared->async_function_instance_hash;
43	
44	    } else {
45	        function->object.shared_hash = vm->shared->arrow_instance_hash;
46	    }
47	
48	    if (async) {
49	        proto = njs_vm_proto(vm, NJS_OBJ_TYPE_ASYNC_FUNCTION);
50	
51	    } else {
52	        proto = njs_vm_proto(vm, NJS_OBJ_TYPE_FUNCTION);
53	    }
54	
55	    function->object.__proto__ = proto;
56	    function->object.type = NJS_FUNCTION;
57	
58	    function->object.extensible = 1;
59	
60	    return function;
61	
62	fail:
63	
64	    njs_memory_error(vm);
65	
66	    return NULL;
67	}
68	
69	
70	njs_function_t *
71	njs_vm_function_alloc(njs_vm_t *vm, njs_function_native_t native,
72	    njs_bool_t shared, njs_bool_t ctor)
73	{
74	    njs_function_t  *function;
75	
76	    function = njs_mp_zalloc(vm->mem_pool, sizeof(njs_function_t));
77	    if (njs_slow_path(function == NULL)) {
78	        njs_memory_error(vm);
79	        return NULL;
80	    }
81	
82	    function->native = 1;
83	    function->ctor = ctor;
84	    function->object.shared = shared;
85	    function->u.native = native;
86	    function->object.shared_hash = vm->shared->function_instance_hash;
87	    function->object.__proto__ = njs_vm_proto(vm, NJS_OBJ_TYPE_FUNCTION);
88	    function->object.type = NJS_FUNCTION;
89	
90	    return function;
91	}
92	
93	
94	njs_function_t *
95	njs_function_value_copy(njs_vm_t *vm, njs_value_t *value)
96	{
97	    njs_function_t  *function, *copy;
98	
99	    function = njs_function(value);
100	
101	    if (!function->object.shared) {
102	        return function;
103	    }
104	
105	    copy = njs_function_copy(vm, function);
106	    if (njs_slow_path(copy == NULL)) {
107	        njs_memory_error(vm);
108	        return NULL;
109	    }
110	
111	    value->data.u.function = copy;
112	
113	    return copy;
114	}
115	
116	
117	njs_int_t
118	njs_function_name_set(njs_vm_t *vm, njs_function_t *function,
119	    njs_value_t *name, const char *prefix)
120	{
121	    u_char               *p;
122	    size_t               len, symbol;
123	    njs_int_t            ret;
124	    njs_value_t          value;
125	    njs_string_prop_t    string;
126	    njs_object_prop_t    *prop;
127	    njs_flathsh_query_t  fhq;
128	
129	    fhq.key_hash = NJS_ATOM_STRING_name;
130	    fhq.replace = 0;
131	    fhq.pool = vm->mem_pool;
132	    fhq.proto = &njs_object_hash_proto;
133	
134	    ret = njs_flathsh_unique_insert(&function->object.hash, &fhq);
135	    if (njs_slow_path(ret != NJS_OK)) {
136	        njs_internal_error(vm, "flathsh insert failed");
137	        return NJS_ERROR;
138	    }
139	
140	    prop = fhq.value;
141	
142	    prop->type = NJS_PROPERTY;
143	    prop->enumerable = 0;
144	    prop->configurable = 1;
145	    prop->writable = 0;
146	    prop->u.value = *name;
147	
148	    symbol = 0;
149	
150	    if (njs_is_symbol(njs_prop_value(prop))) {
151	        symbol = 2;
152	        njs_value_assign(njs_prop_value(prop),
153	                        njs_symbol_description(njs_prop_value(prop)));
154	    }
155	
156	    if (prefix != NULL || symbol != 0) {
157	        if (njs_is_defined(njs_prop_value(prop))) {
158	            njs_value_assign(&value, njs_prop_value(prop));
159	            (void) njs_string_prop(vm, &string, &value);
160	
161	            len = (prefix != NULL) ? njs_strlen(prefix) + 1: 0;
162	            p = njs_string_alloc(vm, njs_prop_value(prop),
163	                                 string.size + len + symbol,
164	                                 string.length + len + symbol);
165	            if (njs_slow_path(p == NULL)) {
166	                return NJS_ERROR;
167	            }
168	
169	            if (len != 0) {
170	                p = njs_cpymem(p, prefix, len - 1);
171	                *p++ = ' ';
172	            }
173	
174	            if (symbol != 0) {
175	                *p++ = '[';
176	            }
177	
178	            p = njs_cpymem(p, string.start, string.size);
179	
180	            if (symbol != 0) {
181	                *p++ = ']';
182	            }
183	
184	        } else {
185	            njs_set_empty_string(vm, njs_prop_value(prop));
186	        }
187	    }
188	
189	    return NJS_OK;
190	}
