193	njs_function_t *
194	njs_function_copy(njs_vm_t *vm, njs_function_t *function)
195	{
196	    size_t             size, n;
197	    njs_value_t        **from, **to;
198	    njs_function_t     *copy;
199	    njs_object_type_t  type;
200	
201	    n = (function->native) ? 0 : function->u.lambda->nclosures;
202	
203	    size = sizeof(njs_function_t) + n * sizeof(njs_value_t *);
204	
205	    copy = njs_mp_alloc(vm->mem_pool, size);
206	    if (njs_slow_path(copy == NULL)) {
207	        return NULL;
208	    }
209	
210	    *copy = *function;
211	
212	    type = njs_function_object_type(vm, function);
213	
214	    copy->object.__proto__ = njs_vm_proto(vm, type);
215	    copy->object.shared = 0;
216	
217	    if (copy->ctor) {
218	        copy->object.shared_hash = vm->shared->function_instance_hash;
219	
220	    } else if (type == NJS_OBJ_TYPE_ASYNC_FUNCTION) {
221	        copy->object.shared_hash = vm->shared->async_function_instance_hash;
222	
223	    } else {
224	        copy->object.shared_hash = vm->shared->arrow_instance_hash;
225	    }
226	
227	    if (n == 0) {
228	        return copy;
229	    }
230	
231	    from = njs_function_closures(function);
232	    to = njs_function_closures(copy);
233	
234	    do {
235	        n--;
236	
237	        to[n] = from[n];
238	
239	    } while (n != 0);
240	
241	    return copy;
242	}
