382	
383	njs_int_t
384	njs_function_lambda_frame(njs_vm_t *vm, njs_function_t *function,
385	    const njs_value_t *this, const njs_value_t *args, njs_uint_t nargs,
386	    njs_bool_t ctor)
387	{
388	    size_t                 n, frame_size;
389	    uint32_t               args_count, value_count, value_size;
390	    njs_value_t            *value, **new;
391	    njs_frame_t            *frame;
392	    njs_native_frame_t     *native_frame;
393	    njs_function_lambda_t  *lambda;
394	
395	    lambda = function->u.lambda;
396	
397	    /*
398	     * Lambda frame has the following layout:
399	     *  njs_frame_t | p0 , p2, ..., pn | v0, v1, ..., vn
400	     *  where:
401	     *  p0, p1, ..., pn - pointers to arguments and locals,
402	     *  v0, v1, ..., vn - values of arguments and locals.
403	     *  n - number of arguments + locals.
404	     *
405	     *  Normally, the pointers point to the values directly after them,
406	     *  but if a value was captured as a closure by an inner function,
407	     *  pn points to a value allocated from the heap.
408	     */
409	
410	    args_count = njs_max(nargs, lambda->nargs);
411	    value_count = args_count + lambda->nlocal;
412	
413	    value_size = value_count * sizeof(njs_value_t *);
414	
415	    frame_size = value_size + (value_count * sizeof(njs_value_t));
416	
417	    native_frame = njs_function_frame_alloc(vm, NJS_FRAME_SIZE + frame_size);
418	    if (njs_slow_path(native_frame == NULL)) {
419	        return NJS_ERROR;
420	    }
421	
422	    /* Local */
423	
424	    new = (njs_value_t **) ((u_char *) native_frame + NJS_FRAME_SIZE);
425	    value = (njs_value_t *) ((u_char *) new + value_size);
426	
427	    n = value_count;
428	
429	    while (n != 0) {
430	        n--;
431	        new[n] = &value[n];
432	        njs_set_invalid(new[n]);
433	    }
434	
435	    native_frame->arguments = value;
436	    native_frame->local = new + args_count;
437	    native_frame->function = function;
438	    native_frame->nargs = nargs;
439	    native_frame->ctor = ctor;
440	    native_frame->native = 0;
441	    native_frame->pc = NULL;
442	
443	    /* Set this and bound arguments. */
444	    *native_frame->local[0] = *this;
445	
446	    if (njs_slow_path(function->global_this
447	                      && njs_is_null_or_undefined(this)))
448	    {
449	        njs_value_assign(native_frame->local[0], &vm->global_value);
450	    }
451	
452	    /* Copy arguments. */
453	
454	    if (args != NULL) {
455	        while (nargs != 0) {
456	            njs_value_assign(value++, args++);
457	            nargs--;
458	        }
459	    }
460	
461	    frame = (njs_frame_t *) native_frame;
462	    frame->exception.catch = NULL;
463	    frame->exception.next = NULL;
464	    frame->previous_active_frame = vm->active_frame;
465	
466	    return NJS_OK;
467	}
