469	
470	njs_native_frame_t *
471	njs_function_frame_alloc(njs_vm_t *vm, size_t size)
472	{
473	    size_t              spare_size, chunk_size;
474	    njs_native_frame_t  *frame;
475	
476	    spare_size = vm->top_frame ? vm->top_frame->free_size : 0;
477	
478	    if (njs_fast_path(size <= spare_size)) {
479	        frame = (njs_native_frame_t *) vm->top_frame->free;
480	        chunk_size = 0;
481	
482	    } else {
483	        spare_size = size + NJS_FRAME_SPARE_SIZE;
484	        spare_size = njs_align_size(spare_size, NJS_FRAME_SPARE_SIZE);
485	
486	        if (spare_size > vm->spare_stack_size) {
487	            njs_range_error(vm, "Maximum call stack size exceeded");
488	            return NULL;
489	        }
490	
491	        frame = njs_mp_align(vm->mem_pool, sizeof(njs_value_t), spare_size);
492	        if (njs_slow_path(frame == NULL)) {
493	            njs_memory_error(vm);
494	            return NULL;
495	        }
496	
497	        chunk_size = spare_size;
498	        vm->spare_stack_size -= spare_size;
499	    }
500	
501	    njs_memzero(frame, sizeof(njs_native_frame_t));
502	
503	    frame->size = chunk_size;
504	    frame->free_size = spare_size - size;
505	    frame->free = (u_char *) frame + size;
506	
507	    frame->previous = vm->top_frame;
508	    vm->top_frame = frame;
509	
510	    return frame;
511	}
