530	njs_int_t
531	njs_function_lambda_call(njs_vm_t *vm, njs_value_t *retval, void *promise_cap)
532	{
533	    uint32_t               n;
534	    njs_int_t              ret;
535	    njs_frame_t            *frame;
536	    njs_value_t            *args, **local, *value;
537	    njs_value_t            **cur_local, **cur_closures;
538	    njs_function_t         *function;
539	    njs_function_lambda_t  *lambda;
540	
541	    frame = (njs_frame_t *) vm->top_frame;
542	    function = frame->native.function;
543	
544	    njs_assert(function->context == NULL);
545	
546	    if (function->global && !function->closure_copied) {
547	        ret = njs_function_capture_global_closures(vm, function);
548	        if (njs_slow_path(ret != NJS_OK)) {
549	            return NJS_ERROR;
550	        }
551	    }
552	
553	    lambda = function->u.lambda;
554	
555	    args = vm->top_frame->arguments;
556	    local = vm->top_frame->local + 1 /* this */;
557	
558	    /* Move all arguments. */
559	
560	    for (n = 0; n < function->args_count; n++) {
561	        if (!njs_is_valid(args)) {
562	            njs_set_undefined(args);
563	        }
564	
565	        *local++ = args++;
566	    }
567	
568	    /* Store current level. */
569	
570	    cur_local = vm->levels[NJS_LEVEL_LOCAL];
571	    cur_closures = vm->levels[NJS_LEVEL_CLOSURE];
572	
573	    /* Replace current level. */
574	
575	    vm->levels[NJS_LEVEL_LOCAL] = vm->top_frame->local;
576	    vm->levels[NJS_LEVEL_CLOSURE] = njs_function_closures(function);
577	
578	    if (lambda->rest_parameters) {
579	        ret = njs_function_rest_parameters_init(vm, &frame->native);
580	        if (njs_slow_path(ret != NJS_OK)) {
581	            return NJS_ERROR;
582	        }
583	    }
584	
585	    /* Self */
586	
587	    if (lambda->self != NJS_INDEX_NONE) {
588	        value = njs_scope_value(vm, lambda->self);
589	
590	        if (!njs_is_valid(value)) {
591	            njs_set_function(value, function);
592	        }
593	    }
594	
595	    vm->active_frame = frame;
596	
597	    ret = njs_vmcode_interpreter(vm, lambda->start, retval, promise_cap, NULL);
598	
599	    /* Restore current level. */
600	    vm->levels[NJS_LEVEL_LOCAL] = cur_local;
601	    vm->levels[NJS_LEVEL_CLOSURE] = cur_closures;
602	
603	    return ret;
604	}
