607	njs_int_t
608	njs_function_native_call(njs_vm_t *vm, njs_value_t *retval)
609	{
610	    njs_int_t              ret;
611	    njs_function_t         *function;
612	    njs_native_frame_t     *native;
613	    njs_function_native_t  call;
614	
615	    native = vm->top_frame;
616	    function = native->function;
617	
618	#ifdef NJS_DEBUG_OPCODE
619	    njs_str_t              name;
620	    njs_value_t            fname, fobj;
621	
622	    if (vm->options.opcode_debug) {
623	        name = njs_str_value("unmapped");
624	
625	        njs_set_function(&fobj, function);
626	
627	        ret = njs_value_property(vm, &fobj, NJS_ATOM_STRING_name, &fname);
628	        if (ret == NJS_OK && njs_is_string(&fname)) {
629	            njs_string_get(vm, &fname, &name);
630	        }
631	
632	        njs_printf("CALL NATIVE %V %P\n", &name, function->u.native);
633	    }
634	#endif
635	
636	    call = function->u.native;
637	
638	    ret = call(vm, &native->arguments[-1], 1 /* this */ + native->nargs,
639	               function->magic8, retval);
640	
641	#ifdef NJS_DEBUG_OPCODE
642	    if (vm->options.opcode_debug) {
643	        njs_printf("CALL NATIVE RETCODE: %i %V %P\n", ret, &name,
644	                   function->u.native);
645	    }
646	#endif
647	
648	    if (njs_slow_path(ret == NJS_ERROR)) {
649	        return ret;
650	    }
651	
652	    njs_vm_scopes_restore(vm, native);
653	
654	    njs_function_frame_free(vm, native);
655	
656	    return NJS_OK;
657	}
