765	njs_int_t
766	njs_function_capture_closure(njs_vm_t *vm, njs_function_t *function,
767	    njs_function_lambda_t *lambda)
768	{
769	    uint32_t            n;
770	    njs_value_t         *value, **closure;
771	    njs_native_frame_t  *frame;
772	
773	    if (lambda->nclosures == 0) {
774	        return NJS_OK;
775	    }
776	
777	    frame = &vm->active_frame->native;
778	
779	    while (frame->native) {
780	        frame = frame->previous;
781	    }
782	
783	    closure = njs_function_closures(function);
784	    n = lambda->nclosures;
785	
786	    do {
787	        n--;
788	
789	        value = njs_scope_value(vm, lambda->closures[n]);
790	
791	        if (njs_is_value_allocated_on_frame(frame, value)) {
792	            value = njs_scope_value_clone(vm, lambda->closures[n], value);
793	            if (njs_slow_path(value == NULL)) {
794	                return NJS_ERROR;
795	            }
796	        }
797	
798	        closure[n] = value;
799	
800	    } while (n != 0);
801	
802	    return NJS_OK;
803	}
