806	njs_inline njs_value_t *
807	njs_function_closure_value(njs_vm_t *vm, njs_native_frame_t *frame,
808	    njs_value_t **scope, njs_index_t index)
809	{
810	    njs_value_t  *value, *newval;
811	
812	    value = scope[njs_scope_index_value(index)];
813	
814	    if (njs_is_value_allocated_on_frame(frame, value)) {
